// ── 5K Trainingsschema (8 weeks, 3x per week) ────────────────────────────────
// Based on RunAcademy/NN opbouwschema voor beginners
// Structure: week 1-3 = run/walk intervals, week 4-6 = longer blocks,
//            week 7-8 = doorrunning opbouw richting 5K

const SCHEMA = {
  1: {
    ma: { type: 'interval',   description: 'Warm-up 5min walking, then 8× (1min running + 1,5min walking), cool-down 5min walking', durationMin: 28, runMin: 8  },
    wo: { type: 'interval',   description: 'Warm-up 5min walking, then 8× (1min running + 1,5min walking), cool-down 5min walking', durationMin: 28, runMin: 8  },
    vr: { type: 'interval',   description: 'Warm-up 5min walking, then 8× (1,5min running + 1,5min walking), cool-down 5min walking', durationMin: 30, runMin: 12 },
  },
  2: {
    ma: { type: 'interval',   description: 'Warm-up 5min walking, then 6× (2min running + 1min walking), cool-down 5min walking', durationMin: 28, runMin: 12 },
    wo: { type: 'interval',   description: 'Warm-up 5min walking, then 6× (2min running + 1min walking), cool-down 5min walking', durationMin: 28, runMin: 12 },
    vr: { type: 'interval',   description: 'Warm-up 5min walking, then 5× (3min running + 1,5min walking), cool-down 5min walking', durationMin: 32, runMin: 15 },
  },
  3: {
    ma: { type: 'interval',   description: 'Warm-up 5min walking, then 4× (4min running + 2min walking), cool-down 5min walking', durationMin: 33, runMin: 16 },
    wo: { type: 'interval',   description: 'Warm-up 5min walking, then 4× (4min running + 2min walking), cool-down 5min walking', durationMin: 33, runMin: 16 },
    vr: { type: 'threshold',    description: 'Warm-up 5min walking, then 3× (6min running + 2min walking), cool-down 5min walking', durationMin: 33, runMin: 18 },
  },
  4: {
    ma: { type: 'interval',   description: 'Warm-up 5min walking, then 3× (6min running + 2min walking), cool-down 5min walking', durationMin: 33, runMin: 18 },
    wo: { type: 'endurance',   description: 'Warm-up 5min walking, then 20min easy run (Z2), cool-down 5min walking', durationMin: 30, runMin: 20 },
    vr: { type: 'interval',   description: 'Warm-up 5min walking, then 2× (8min running + 2min walking), cool-down 5min walking', durationMin: 30, runMin: 16 },
  },
  5: {
    ma: { type: 'endurance',   description: 'Warm-up 5min walking, then 22min easy run (Z2), cool-down 5min walking', durationMin: 32, runMin: 22 },
    wo: { type: 'interval',   description: 'Warm-up 5min walking, then 4× (5min running + 1min walking), cool-down 5min walking', durationMin: 31, runMin: 20 },
    vr: { type: 'endurance',   description: 'Warm-up 5min walking, then 25min easy run (Z2), cool-down 5min walking', durationMin: 35, runMin: 25 },
  },
  6: {
    ma: { type: 'endurance',   description: 'Warm-up 5min walking, then 25min easy run (Z2), cool-down 5min walking', durationMin: 35, runMin: 25 },
    wo: { type: 'tempo',      description: 'Warm-up 10min easy, then 10min iets sneller (Z3), cool-down 10min easy', durationMin: 30, runMin: 30 },
    vr: { type: 'endurance',   description: 'Warm-up 5min walking, then 28min easy run (Z2), cool-down 5min walking', durationMin: 38, runMin: 28 },
  },
  7: {
    ma: { type: 'endurance',   description: '30min easy run (Z2) without walking breaks', durationMin: 30, runMin: 30 },
    wo: { type: 'tempo',      description: 'Warm-up 10min easy, 12min tempo (Z3-Z4), cool-down 8min easy', durationMin: 30, runMin: 30 },
    vr: { type: 'lange loop', description: '33min easy run (Z2) — langste training tot nu toe', durationMin: 33, runMin: 33 },
  },
  8: {
    ma: { type: 'endurance',   description: '30min easy run (Z2) — tapering, iets easyer', durationMin: 30, runMin: 30 },
    wo: { type: 'activatie',  description: '20min easy inrunning + 4× 1min versnelling, cool-down 5min', durationMin: 25, runMin: 25 },
    vr: { type: '5K poging',  description: '🏁 RACE DAY! Warm-up 10min walking, then zo ver en snel als je kunt running — stuur je tijd in!', durationMin: 45, runMin: 40 },
  },
};

// ── Bepaal current training week ─────────────────────────────────────────────
// Gebruik n8n static data om startdate bij te houden
const staticData = $getWorkflowStaticData('global');

// Eerste run: sla startdate op
if (!staticData.schema5KStartDatum) {
  staticData.schema5KStartDatum = new Date().toISOString().split('T')[0];
}

const startDatum = new Date(staticData.schema5KStartDatum);
const today    = new Date();
const dagVerschil = Math.floor((today - startDatum) / (1000 * 60 * 60 * 24));
const weekNr     = Math.min(Math.floor(dagVerschil / 7) + 1, 8);
const dagInWeek  = dagVerschil % 7; // 0=ma, 1=di, 2=wo, 3=do, 4=vr, 5=za, 6=zo

// Bepaal welke trainingsdag today is (ma/wo/vr = trainingsdag, rest = rust)
const dagNamen = ['ma', 'di', 'wo', 'do', 'vr', 'za', 'zo'];
const dagNaamVandaag = dagNamen[dagInWeek];
const weekSchema = SCHEMA[weekNr] || SCHEMA[8];
const trainingVandaag = weekSchema[dagNaamVandaag] || null;

// Volgende trainingsdag bepalen
let nextTraining = null;
let nextNaam = null;
for (let i = 1; i <= 7; i++) {
  const nextDag = dagNamen[(dagInWeek + i) % 7];
  if (weekSchema[nextDag]) {
    const dateVolgende = new Date(today);
    dateVolgende.setDate(dateVolgende.getDate() + i);
    nextTraining = weekSchema[nextDag];
    nextNaam = dateVolgende.toLocaleDateString('nl-NL', { weekday: 'long', day: 'numeric', month: 'short' });
    break;
  }
}

// Vorige training (voor context)
let previousTraining = null;
for (let i = 1; i <= 7; i++) {
  const previousDag = dagNamen[((dagInWeek - i) + 7) % 7];
  if (weekSchema[previousDag]) {
    previousTraining = weekSchema[previousDag];
    break;
  }
}

// Voortgang berekenen
const totaalTrainingsdagen = Object.keys(SCHEMA).reduce((s, w) => s + Object.keys(SCHEMA[w]).length, 0);
const gedaanTrainingsdagen = (weekNr - 1) * 3 + Object.keys(weekSchema).filter(d => {
  const dagIdx = dagNamen.indexOf(d);
  return dagIdx <= dagInWeek;
}).length;
const voortgangPct = Math.round(gedaanTrainingsdagen / totaalTrainingsdagen * 100);

// Schema samenvatting voor Groq
const scheduleContext = {
  weekNr,
  dagNaamVandaag,
  isTrainingsdag: trainingVandaag !== null,
  startDatum: staticData.schema5KStartDatum,
  dagVerschil,
  voortgangPct,
  gedaanTrainingsdagen,
  totaalTrainingsdagen,

  // Vandaag
  todayTraining: trainingVandaag ? {
    type:        trainingVandaag.type,
    description: trainingVandaag.description,
    durationMin:     trainingVandaag.durationMin,
    runMin:     trainingVandaag.runMin,
  } : null,

  // Volgende training
  nextTraining: nextTraining ? {
    date:        nextNaam,
    type:         nextTraining.type,
    description: nextTraining.description,
    durationMin:      nextTraining.durationMin,
  } : null,

  // Hele week overzicht
  weekOverzicht: Object.entries(weekSchema).map(([dag, t]) => `${dag}: ${t.type} — ${t.durationMin}min`).join(' | '),

  // Race prediction context
  huidig5KTijd: null, // wordt ingevuld door garmin data
};

// ── Readiness-adjustment van de training ─────────────────────────────────────
const garminData = $input.first().json;
scheduleContext.huidig5KTijd = garminData.racePredictions?.vijfKm ?? null;

const readiness = garminData.trainingReadiness;
const score     = readiness?.score ?? 100;
const level     = (readiness?.level ?? '').toUpperCase();
const acuut     = garminData.trainingStatus?.acuutLoad    ?? null;
const chronisch = garminData.trainingStatus?.chronischLoad ?? null;
const acwrStatus = garminData.trainingStatus?.acwrStatus   ?? null;

// Bepaal adjustmentsniveau
// Groen  (≥70, acwrStatus OPTIMAL/HIGH): volg schema normaal
// Oranje (40-69, of acwrStatus LOW):     lichter uitvoeren
// Rood   (<40, of level LOW/RECOVERY):   rustdag aanbevolen

let adjustment = 'normaal';
let adjustmentReden = null;
let adjustmentTraining = null;

if (score < 40 || level === 'LOW' || level === 'RECOVERY' || level === 'POOR') {
  adjustment = 'rust';
  adjustmentReden = `Readiness ${score}/100 (${level}) — lichamelijke belasting te hoog voor training today.`;
  adjustmentTraining = {
    type: 'recovery walk',
    description: `No running training today. Optioneel: 20-30 minuten easy walk at Z1 (heart rate onder ${Math.round((220 - 54) * 0.6)}bpm). Richt je op sleep en voeding.`,
    durationMin: 0,
    runMin: 0,
  };
} else if (score < 70 || acwrStatus === 'LOW' || (acuut !== null && chronisch !== null && acuut < chronisch * 0.4)) {
  adjustment = 'licht';
  adjustmentReden = `Readiness ${score}/100 (${level}) — schema aanpassen naar lichtere variant.`;
  // Maak de geplande training lichter
  if (scheduleContext.todayTraining) {
    const orig = scheduleContext.todayTraining;
    const kortereLoopMin = Math.max(Math.round(orig.runMin * 0.65), 8);
    adjustmentTraining = {
      type: orig.type + ' (licht)',
      description: orig.description
        .replace(/(\d+)min running/g, (_, m) => `${Math.round(m * 0.65)}min running`)
        .replace(/(\d+)× \(/g, (_, n) => `${Math.max(Math.round(n * 0.65), 2)}× (`)
        + ` — LICHTERE VARIANT: loop in Z1-Z2 (heart rate onder ${Math.round((220 - 54) * 0.7)}bpm), stop als je moe voelt.`,
      durationMin: Math.round(orig.durationMin * 0.75),
      runMin: kortereLoopMin,
    };
  }
} else {
  adjustment = 'normaal';
  adjustmentReden = `Readiness ${score}/100 (${level}) — schema volgen zoals gepland.`;
  adjustmentTraining = scheduleContext.todayTraining;
}

// Voeg toe aan scheduleContext
scheduleContext.adjustment        = adjustment;          // 'normaal' | 'licht' | 'rust'
scheduleContext.adjustmentReden   = adjustmentReden;
scheduleContext.adjustmentTraining = adjustmentTraining; // de aangepaste training
scheduleContext.origineelTraining  = scheduleContext.todayTraining; // bewaar origineel
scheduleContext.readinessScore    = score;
scheduleContext.readinessLevel    = level;

// Overschrijf todayTraining met de aangepaste versie
if (adjustmentTraining) {
  scheduleContext.todayTraining = adjustmentTraining;
}

return [{ json: { ...garminData, scheduleContext } }];

// Sla nieuwe advice op in n8n Static Data
const staticData = $getWorkflowStaticData('global');
if (!staticData.advice) staticData.advice = [];
if (!staticData.gegenereerd_op) staticData.gegenereerd_op = [];

const input       = $input.first().json;
const { analyse, garminData } = input;
const today     = new Date().toISOString();
const dateLabel  = today.split('T')[0];

// Secties om advice uit te halen
const secties = [
  { marker: 'Top 5 Slapadvice',   categorie: 'Slaap' },
  { marker: 'Top 5 Beweegadvice', categorie: 'Beweging' },
  { marker: 'Doelen voor next', categorie: 'Doel' },
  { marker: 'Acties voor today',  categorie: 'Actie' },
];

const nieuweAdviezen = [];
let overgeslagen = 0;

for (const sectie of secties) {
  const idx = analyse.indexOf(sectie.marker);
  if (idx === -1) continue;

  // Pak ~600 tekens na de sectie-header
  const stuk = analyse.slice(idx, idx + 600);
  const re = /^\d+\.\s+(.+)$/gm;
  let m;

  while ((m = re.exec(stuk)) !== null) {
    const titelRuw = m[1].trim().replace(/\[.*?\]/g, '').trim();
    if (titelRuw.length < 5) continue;

    const key = titelRuw.slice(0, 60).toLowerCase();
    const bestaat = staticData.advice.some(
      a => a.titel.slice(0, 60).toLowerCase() === key
    );

    if (!bestaat) {
      nieuweAdviezen.push({
        id:         `${dateLabel}-${sectie.categorie}-${nieuweAdviezen.length}`,
        date:      today,
        categorie:  sectie.categorie,
        titel:      titelRuw,
        feedback:   null,
        herhaalCount: 0
      });
    } else {
      // Verhoog teller op bestaand advies
      const bestaand = staticData.advice.find(
        a => a.titel.slice(0, 60).toLowerCase() === key
      );
      if (bestaand) bestaand.herhaalCount = (bestaand.herhaalCount || 0) + 1;
      overgeslagen++;
    }
  }
}

// Voeg nieuwe advice toe en bewaar max 200 (FIFO)
staticData.advice = [...staticData.advice, ...nieuweAdviezen].slice(-200);
staticData.gegenereerd_op = [...staticData.gegenereerd_op, today].slice(-90);

// Statistieken voor rapport
const geheugenStats = {
  totaalAdviezen: staticData.advice.length,
  nieuweVandaag:  nieuweAdviezen.length,
  overgeslagen
};

return [{ json: { analyse, garminData, geheugenStats } }];

// Laad adviesgeheugen via n8n Static Data (no fs, no externe modules nodig)
const staticData = $getWorkflowStaticData('global');

// Initialiseer als leeg als het nog niet bestaat
if (!staticData.advice) staticData.advice = [];
if (!staticData.gegenereerd_op) staticData.gegenereerd_op = [];

const advice = staticData.advice;
const aantalAdviezen = advice.length;

// Sorteer op date, pak laatste 40
const laatste40 = [...advice]
  .sort((a, b) => new Date(b.date) - new Date(a.date))
  .slice(0, 40);

// Groepeer per categorie
const perCategorie = {};
for (const adv of laatste40) {
  const cat = adv.categorie || 'Overig';
  if (!perCategorie[cat]) perCategorie[cat] = [];
  perCategorie[cat].push(adv);
}

// Bouw leesbare tekst voor de Groq-prompt
let geheugenTekst = `## PREVIOUSLY GIVEN ADVICE (laatste 40 van totaal ${aantalAdviezen})\n`;
geheugenTekst += `Vermijd repetition van deze advice tenzij data aantoont dat het nog steeds kritiek is.\n\n`;

if (aantalAdviezen === 0) {
  geheugenTekst += '_No previous advice yet — this is the first run._\n';
} else {
  for (const [cat, items] of Object.entries(perCategorie)) {
    geheugenTekst += `### ${cat}\n`;
    for (const item of items) {
      const date = (item.date || '').split('T')[0];
      let regel = `- [${date}] ${item.titel}`;
      if (item.feedback) regel += ` → Feedback: "${item.feedback}"`;
      geheugenTekst += regel + '\n';
    }
    geheugenTekst += '\n';
  }
}

// Geef garminData + geheugencontext door
const garminData = $input.first().json;
return [{ json: {
  ...garminData,
  geheugen: { advice, gegenereerd_op: staticData.gegenereerd_op },
  geheugenTekst,
  aantalAdviezen
}}];

const { analyse, garminData, geheugenStats } = $input.first().json;
const gem  = garminData.gemiddelden;
const geheugenbadge = geheugenStats
  ? `<table width="100%" cellpadding="0" cellspacing="0"><tr><td style="background:#f0fdf4;border:1px solid #86efac;border-radius:10px;padding:12px 16px;font-size:13px;color:#166534;font-family:Arial,sans-serif">
       🧠 <strong>Adviesgeheugen actief</strong> — ${geheugenStats.nieuweVandaag} nieuwe · ${geheugenStats.overgeslagen ?? 0} overgeslagen · Totaal ${geheugenStats.totaalAdviezen}
     </td></tr></table><br>`
  : '';
const tr   = garminData.trends;
const SD   = garminData.sleepData    || [];
const STAP = garminData.stapsData    || [];
const HR   = garminData.heart rateData || [];
const ST   = garminData.stressData   || [];
const HRV  = garminData.hrvData      || [];
const GW   = garminData.weightData  || [];
const TR   = garminData.trainingReadiness;
const SC   = garminData.scheduleContext || null;
const TS   = garminData.trainingStatus;
const VO2  = garminData.vo2maxData   || [];
const RACE = garminData.racePredictions;

const nu = new Date();
const stapDoel = gem.stapDoel || 8000;
const dateStr = nu.toLocaleDateString('nl-NL', { weekday:'long', year:'numeric', month:'long', day:'numeric' });

function formatDatum(isoStr) {
  if (!isoStr) return '?';
  const dt = new Date(isoStr + 'T00:00:00');
  const dag = dt.toLocaleDateString('nl-NL', { weekday: 'long' });
  const d2  = dt.toLocaleDateString('nl-NL', { day: 'numeric', month: 'long' });
  return `${d2} (${dag})`;
}
const dagLabels = SD.map(d => {
  const dt = new Date(d.date);
  return dt.toLocaleDateString('nl-NL',{weekday:'short'}).slice(0,2) + dt.getDate();
});

// ─── GRAFIEK HELPERS (Gmail-safe: alleen tables/td) ───────────────────────
const GRAFIEK_BREEDTE = 280;
const N = dagLabels.length || 7;
const COL_W = Math.floor(GRAFIEK_BREEDTE / N);
const BAR_W = Math.max(COL_W - 6, 8);

function staafGrafiek(items, hoogte, barDataFn, dagLabelsFn) {
  const cols = items.map((item, i) => {
    const bars = barDataFn(item);
    const dagLbl = dagLabelsFn ? dagLabelsFn(i) : (dagLabels[i] || '');
    const pixelBars = bars.map(b => ({
      ...b, px: Math.max(Math.round((b.pct || 0) * hoogte / 100), (b.pct > 0 ? 2 : 0))
    })).filter(b => b.px > 0);
    const totaalPx = pixelBars.reduce((s, b) => s + b.px, 0);
    const leegte = Math.max(hoogte - totaalPx, 0);
    const labelBoven = bars.find(b => b.label)?.label || '';
    const labelKleur = pixelBars.length > 0 ? pixelBars[pixelBars.length - 1].kleur : '#999';
    const barsVanBovenNaarOnder = [...pixelBars].reverse();
    let rijen = '';
    if (leegte > 0) rijen += `<tr><td width="${BAR_W}" height="${leegte}" style="height:${leegte}px;font-size:0;line-height:0">&nbsp;</td></tr>`;
    barsVanBovenNaarOnder.forEach(b => {
      rijen += `<tr><td width="${BAR_W}" height="${b.px}" style="background:${b.kleur};height:${b.px}px;font-size:0;line-height:0">&nbsp;</td></tr>`;
    });
    return `<td width="${COL_W}" style="vertical-align:bottom;text-align:center;padding:0 3px">
      ${labelBoven ? `<div style="font-size:9px;font-weight:700;color:${labelKleur};font-family:Arial,sans-serif;line-height:1.2;margin-bottom:1px">${labelBoven}</div>` : ''}
      <table cellpadding="0" cellspacing="0" width="${BAR_W}" style="margin:0 auto;border-collapse:collapse">${rijen}</table>
      <div style="font-size:9px;color:#aaa;font-family:Arial,sans-serif;margin-top:3px;line-height:1.2">${dagLbl}</div>
    </td>`;
  }).join('');
  return `<table cellpadding="0" cellspacing="0" style="border-collapse:collapse;width:${GRAFIEK_BREEDTE}px"><tr valign="bottom">${cols}</tr></table>`;
}

function puntGrafiek(items, hoogte, valFn, kleur, labelFn) {
  const waarden = items.map(valFn).map(v => (v && v > 0) ? v : null);
  const geldig  = waarden.filter(v => v !== null);
  if (geldig.length === 0) {
    return `<table cellpadding="0" cellspacing="0" style="width:${GRAFIEK_BREEDTE}px"><tr><td style="text-align:center;color:#ccc;font-size:11px;padding:16px 0;font-family:Arial,sans-serif">No data available</td></tr></table>`;
  }
  const minV = Math.min(...geldig);
  const maxV = Math.max(...geldig);
  const range = maxV - minV || 1;
  const dotH = 8;
  const cols = items.map((item, i) => {
    const val = waarden[i];
    const dagLbl = dagLabels[i] || '';
    if (val === null) {
      return `<td width="${COL_W}" style="text-align:center;padding:0 3px"><div style="height:${hoogte + 16}px"></div><div style="font-size:9px;color:#aaa;font-family:Arial,sans-serif">${dagLbl}</div></td>`;
    }
    const pct = (val - minV) / range;
    const dotVanOnder = Math.round(pct * (hoogte - dotH));
    const boven = hoogte - dotVanOnder - dotH;
    const label = labelFn ? labelFn(val) : String(val);
    return `<td width="${COL_W}" style="vertical-align:top;text-align:center;padding:0 3px">
      <table cellpadding="0" cellspacing="0" width="100%" style="border-collapse:collapse">
        <tr><td height="${Math.max(boven - 14, 0)}" style="height:${Math.max(boven - 14, 0)}px;font-size:0;line-height:0">&nbsp;</td></tr>
        <tr><td style="text-align:center;font-size:9px;font-weight:700;color:${kleur};font-family:Arial,sans-serif;line-height:1.2">${label}</td></tr>
        <tr><td height="4" style="height:4px;font-size:0;line-height:0">&nbsp;</td></tr>
        <tr><td style="text-align:center"><div style="width:8px;height:8px;background:${kleur};border-radius:50%;border:2px solid white;outline:1px solid ${kleur};margin:0 auto;font-size:0;line-height:0">&nbsp;</div></td></tr>
        <tr><td height="${Math.max(dotVanOnder, 0)}" style="height:${Math.max(dotVanOnder, 0)}px;font-size:0;line-height:0">&nbsp;</td></tr>
      </table>
      <div style="font-size:9px;color:#aaa;font-family:Arial,sans-serif;margin-top:2px;line-height:1.2">${dagLbl}</div>
    </td>`;
  }).join('');
  return `<table cellpadding="0" cellspacing="0" style="border-collapse:collapse;width:${GRAFIEK_BREEDTE}px"><tr valign="top">${cols}</tr></table>`;
}

// ─── GRAFIEKEN ────────────────────────────────────────────────────────────

// G1: Slaap gestapeld
const maxSlaap = Math.max(...SD.map(d => d.totaalUur || 0), 9);
const grafiek1 = staafGrafiek(SD, 100,
  d => [
    { pct: (d.lightUur || 0) / maxSlaap * 100, kleur: '#90caf9' },
    { pct: (d.remUur   || 0) / maxSlaap * 100, kleur: '#7c4dff' },
    { pct: (d.diepUur  || 0) / maxSlaap * 100, kleur: '#1565c0', label: d.totaalUur > 0 ? d.totaalUur + 'u' : '' }
  ]
);

// G1b: Slaapscore
const grafiek1b = puntGrafiek(SD, 50, d => d.score, '#ff6f00');

// G2: Stappen
const maxStap = Math.max(...STAP.map(d => Math.max(d.steps || 0, d.stapDoel || 0)), stapDoel);
const grafiek2 = staafGrafiek(STAP, 90,
  d => {
    const pct = (d.steps || 0) / maxStap * 100;
    const klr = (d.steps || 0) >= (d.stapDoel || stapDoel) ? '#4caf50'
              : (d.steps || 0) >= (d.stapDoel || stapDoel) * 0.75 ? '#ff9800' : '#f44336';
    return [{ pct, kleur: klr, label: d.steps > 0 ? (Math.round(d.steps / 100) / 10).toFixed(1) + 'k' : '' }];
  }
);

// G3a: Rustpols
const hrMerged = HR.map((d, i) => ({ ...d, rustpols: d.rustpols || (STAP[i] && STAP[i].rustpols) || null }));
const grafiek3a = puntGrafiek(hrMerged, 70, d => d.rustpols, '#e53935');

// G3b: HRV
const grafiek3b = puntGrafiek(HRV, 70, d => d.weekGem, '#00897b');

// G4: Stress
const stressComponentenSom = ST.map(d => (d.rustMin||0)+(d.laagMin||0)+(d.middenMin||0)+(d.hoogMin||0));
