let grafiek4;
if (heeftStressComponenten) {
  const maxStress = Math.max(...stressComponentenSom, 60);
  grafiek4 = staafGrafiek(ST, 90, d => [
    { pct: (d.rustMin   || 0) / maxStress * 100, kleur: '#a5d6a7' },
    { pct: (d.laagMin   || 0) / maxStress * 100, kleur: '#ffe082' },
    { pct: (d.middenMin || 0) / maxStress * 100, kleur: '#ffb74d' },
    { pct: (d.hoogMin   || 0) / maxStress * 100, kleur: '#ef5350', label: d.gemStress ? String(d.gemStress) : '' }
  ]);
} else if (heeftStressPunten) {
  grafiek4 = puntGrafiek(stressPuntData, 70, d => d.gemStress, '#ff9800', v => String(v));
} else {
  grafiek4 = '<div style="text-align:center;color:#ccc;font-size:11px;padding:16px;font-family:Arial,sans-serif">No stress data available</div>';
