    if (!d.bbHoog && !d.bbLaag) return [{ pct: 0, kleur: '#eee' }];
    const klr = (d.bbHoog || 0) >= 60 ? '#42a5f5' : (d.bbHoog || 0) >= 40 ? '#ffb74d' : '#ef5350';
    return [
      { pct: d.bbLaag || 0, kleur: '#f0f0f0' },
      { pct: Math.max((d.bbHoog || 0) - (d.bbLaag || 0), 1), kleur: klr, label: d.bbHoog ? String(d.bbHoog) : '' }
