const BASE = 'http://[your NAS IP]:8085';

function dateGeleden(n) {
  const d = new Date();
  d.setDate(d.getDate() - n);
  return d.toISOString().split('T')[0];
}

const dates = [];
for (let i = 9; i >= 0; i--) dates.push(dateGeleden(i));
const today = dates[dates.length - 1];

// ── Per dag arrays ────────────────────────────────────────────────────────────
const sleepData    = [];
const stapsData    = [];
const heart rateData = [];
const stressData   = [];
const hrvData      = [];
const weightData  = [];
const hrZoneData   = [];

for (const date of dates) {

  // SLAAP
  try {
    const r = await this.helpers.request({ method:'GET', url:`${BASE}/sleep?date=${date}`, json:true });
    const dto = r?.dailySleepDTO || {};
    const scores = dto.sleepScores || {};
    sleepData.push({
      date,
      totaalUur:  Math.round((dto.sleepTimeSeconds  ||0)/360)/10,
      diepUur:    Math.round((dto.deepSleepSeconds   ||0)/360)/10,
      remUur:     Math.round((dto.remSleepSeconds    ||0)/360)/10,
      lightUur:   Math.round((dto.lightSleepSeconds  ||0)/360)/10,
      wakkerUur:  Math.round((dto.awakeSleepSeconds  ||0)/360)/10,
      score:      scores.overall?.value      ?? null,
      scoreDeep:  scores.deepSleep?.value    ?? null,
      scoreRem:   scores.remSleep?.value     ?? null,
      scoreRest:  scores.restfulness?.value  ?? null,
      scoreDur:   scores.duration?.value     ?? null,
      spo2Gem:    dto.averageSpO2Value        ?? null,
      spo2Min:    dto.lowestSpO2Value         ?? null,
      hrv:        dto.avgOvernightHrv         ?? null,
      rustpols:   dto.restingHeartRate        ?? null,
      bedtijd:    dto.sleepStartTimestampLocal ? new Date(dto.sleepStartTimestampLocal).toTimeString().slice(0,5) : null,
      waaktijd:   dto.sleepEndTimestampLocal   ? new Date(dto.sleepEndTimestampLocal).toTimeString().slice(0,5)   : null,
      ademhaling: dto.averageRespirationValue  ?? null,
    });
  } catch(e) {
    sleepData.push({ date, totaalUur:0, diepUur:0, remUur:0, lightUur:0, wakkerUur:0, score:null, scoreDeep:null, scoreRem:null, scoreRest:null, scoreDur:null, spo2Gem:null, spo2Min:null, hrv:null, rustpols:null, bedtijd:null, waaktijd:null, ademhaling:null });
  }

  // STATS
  try {
    const r = await this.helpers.request({ method:'GET', url:`${BASE}/stats?date=${date}`, json:true });
    stapsData.push({
      date,
      steps:         r.totalSteps                  ?? 0,
      stapDoel:        r.dailyStepGoal               ?? 0,
      stapPct:         r.dailyStepGoal ? Math.round((r.totalSteps||0)/r.dailyStepGoal*100) : 0,
      afstandM:        r.totalDistanceMeters          ?? 0,
      calActief:       r.activeKilocalories           ?? 0,
      calTotaal:       r.totalKilocalories            ?? 0,
      calBMR:          r.bmrKilocalories              ?? 0,
      gemStress:       r.averageStressLevel           ?? null,
      maxStress:       r.maxStressLevel               ?? null,
      bbHoog:          r.bodyBatteryHighestValue      ?? null,
      bbLaag:          r.bodyBatteryLowestValue       ?? null,
      bbHuidig:        r.bodyBatteryMostRecentValue   ?? null,
      bbDelta:         (r.bodyBatteryHighestValue??0)-(r.bodyBatteryLowestValue??0),
      rustpols:        r.restingHeartRate             ?? null,
      maxHR:           r.maxHeartRate                 ?? null,
      intensiteitMid:  r.moderateIntensityMinutes     ?? 0,
      intensiteitHoog: r.vigorousIntensityMinutes     ?? 0,
      sedentarySec:    r.sedentarySeconds             ?? 0,
      sleepSec:        r.sleepingSeconds              ?? 0,
      etages:          r.floorsAscended               ?? null,
      spo2Gem:         r.averageSpo2                  ?? null,
      ademhaling:      r.avgWakingRespirationValue    ?? null,
    });
  } catch(e) {
    stapsData.push({ date, steps:0, stapDoel:0, stapPct:0, afstandM:0, calActief:0, calTotaal:0, calBMR:0, gemStress:null, maxStress:null, bbHoog:null, bbLaag:null, bbHuidig:null, bbDelta:0, rustpols:null, maxHR:null, intensiteitMid:0, intensiteitHoog:0, sedentarySec:0, sleepSec:0, etages:null, spo2Gem:null, ademhaling:null });
  }

  // HARTSLAG
  try {
    const r = await this.helpers.request({ method:'GET', url:`${BASE}/heart rate?date=${date}`, json:true });
    heart rateData.push({
      date,
      rustpols:    r.restingHeartRate                    ?? null,
      minHR:       r.minHeartRate                        ?? null,
      maxHR:       r.maxHeartRate                        ?? null,
      gem7daags:   r.lastSevenDaysAvgRestingHeartRate    ?? null,
    });
  } catch(e) {
    heart rateData.push({ date, rustpols:null, minHR:null, maxHR:null, gem7daags:null });
  }

  // STRESS
  try {
    const r = await this.helpers.request({ method:'GET', url:`${BASE}/stress?date=${date}`, json:true });
    const stressGem = r.averageStressLevel ?? r.avgStressLevel ?? r.dailyStressAvg ?? null;
    const stressMax = r.maxStressLevel ?? r.maxStress ?? null;
    const toDur = (v) => v ? Math.round(v / 60) : 0;
    stressData.push({
      date,
      gemStress: stressGem,
      maxStress: stressMax,
      rustMin:   toDur(r.restStressDuration   ?? r.restDuration   ?? 0),
      laagMin:   toDur(r.lowStressDuration    ?? r.lowDuration    ?? 0),
      middenMin: toDur(r.mediumStressDuration ?? r.mediumDuration ?? 0),
      hoogMin:   toDur(r.highStressDuration   ?? r.highDuration   ?? 0),
      totaalMin: toDur(r.totalStressDuration  ?? r.totalDuration  ?? 0),
    });
  } catch(e) {
    stressData.push({ date, gemStress:null, maxStress:null, rustMin:0, laagMin:0, middenMin:0, hoogMin:0, totaalMin:0 });
  }

  // HRV
  try {
    const r = await this.helpers.request({ method:'GET', url:`${BASE}/hrv?date=${date}`, json:true });
    const s = r?.hrvSummary || {};
    const dagWaarden = Array.isArray(r?.hrvReadings)
      ? r.hrvReadings.map(v => v?.hrvValue ?? v ?? null).filter(v => v !== null)
      : [];
    hrvData.push({
      date,
      weekGem:      s.weeklyAvg           ?? null,
      previousNacht:  s.lastNight           ?? null,
      vijfDaags:    s.lastFiveDaysAvg     ?? null,
      status:       s.status              ?? null,
      baselineLaag: s.baselineLowUpper    ?? null,
      baselineHoog: s.baselineBalancedLow ?? null,
      nachMin:      dagWaarden.length ? Math.min(...dagWaarden) : null,
      nachMax:      dagWaarden.length ? Math.max(...dagWaarden) : null,
      rmssd:        s.rmssd ?? s.avgHRV ?? null,
    });
  } catch(e) {
    hrvData.push({ date, weekGem:null, previousNacht:null, vijfDaags:null, status:null, baselineLaag:null, baselineHoog:null, nachMin:null, nachMax:null, rmssd:null });
  }

  // GEWICHT
  try {
    const r = await this.helpers.request({ method:'GET', url:`${BASE}/weight?date=${date}`, json:true });
    const m = r?.dateWeightList?.[0];
    weightData.push({
      date,
      weightKg:    m?.weight ? Math.round(m.weight/10)/100 : null,
      bmi:          m?.bmi          ?? null,
      vetPct:       m?.bodyFat      ?? null,
      spierpct:     m?.muscleMass   ?? null,
      waterPct:     m?.bodyWater    ?? null,
    });
  } catch(e) {
    weightData.push({ date, weightKg:null, bmi:null, vetPct:null, spierpct:null, waterPct:null });
  }

  // HARTSLAG ZONES
  try {
    const r = await this.helpers.request({ method:'GET', url:`${BASE}/heart ratezones?date=${date}`, json:true });
    const zones = Array.isArray(r?.heartRateZones) ? r.heartRateZones
                : Array.isArray(r?.zones) ? r.zones
                : Array.isArray(r) ? r : [];
    const toMin = (s) => s ? Math.round(s / 60) : 0;
    hrZoneData.push({
      date,
      zone1Min: toMin(zones[0]?.secsInZone ?? zones[0]?.seconds ?? 0),
      zone2Min: toMin(zones[1]?.secsInZone ?? zones[1]?.seconds ?? 0),
      zone3Min: toMin(zones[2]?.secsInZone ?? zones[2]?.seconds ?? 0),
      zone4Min: toMin(zones[3]?.secsInZone ?? zones[3]?.seconds ?? 0),
      zone5Min: toMin(zones[4]?.secsInZone ?? zones[4]?.seconds ?? 0),
    });
  } catch(e) {
    hrZoneData.push({ date, zone1Min:0, zone2Min:0, zone3Min:0, zone4Min:0, zone5Min:0 });
  }
}

// ── Activiteiten (laatste 15) ─────────────────────────────────────────────────
let activitiesTekst = 'No activities found';
let activitiesData  = [];
try {
  const r = await this.helpers.request({ method:'GET', url:`${BASE}/activities?limit=15`, json:true });
  if (Array.isArray(r) && r.length > 0) {
    activitiesData = r;
    activitiesTekst = r.slice(0,10).map(a => {
      const naam   = a.activityName || a.activityType?.typeKey || 'activity';
      const date  = (a.startTimeLocal||'').slice(0,10);
      const duur   = Math.round((a.duration||0)/60);
      const km     = a.distance    ? (Math.round(a.distance/100)/10)+'km' : '';
      const hr     = a.averageHR   ? `gem HR:${a.averageHR}bpm` : '';
      const cal    = a.calories    ? `${a.calories}kcal` : '';
      const tempo  = a.averageSpeed && a.activityType?.typeKey?.includes('running')
        ? `${Math.round(1000/a.averageSpeed/60)}:${String(Math.round(1000/a.averageSpeed%60)).padStart(2,'0')}/km` : '';
      return `${date}: ${naam} — ${duur}min ${[km,hr,cal,tempo].filter(Boolean).join(' ')}`;
    }).join('\n');
  }
} catch(e) {}

// ── TRAINING READINESS (today) ──────────────────────────────────────────────
// Echte response: [{score:72, level:"MODERATE", feedbackShort:"LISTEN_TO_YOUR_BODY",
//   feedbackLong:"MOD_HRV_UNBALANCED", sleepScore:80, recoveryTime:1, acuteLoad:56, ...}]
let trainingReadiness = null;
try {
  const r = await this.helpers.request({ method:'GET', url:`${BASE}/training-readiness?date=${today}`, json:true });
  const item = Array.isArray(r) ? r[r.length - 1] : r;
  if (item && item.score != null) {
    trainingReadiness = {
      score:        item.score,
      level:        item.level          ?? null,   // "MODERATE", "HIGH", "LOW"
      feedbackKort: item.feedbackShort  ?? null,   // "LISTEN_TO_YOUR_BODY"
      feedbackLang: item.feedbackLong   ?? null,   // "MOD_HRV_UNBALANCED"
      sleepScore:   item.sleepScore     ?? null,
      recoveryTime: item.recoveryTime   ?? null,
      acuteLoad:    item.acuteLoad      ?? null,
      hrv:          item.hrvWeeklyAverage ?? null,
      // Vertaal level naar Nederlands
      levelNL: (() => {
        const l = (item.level || '').toUpperCase();
        if (l === 'HIGH' || l === 'EXCELLENT')  return 'Klaar voor zware training';
        if (l === 'MODERATE' || l === 'MEDIUM') return 'Matige trainingsbereidheid';
        if (l === 'LOW' || l === 'POOR')        return 'Rust aanbevolen';
        if (l === 'RECOVERY')                   return 'Hersteldag aanbevolen';
        return item.level ?? null;
      })(),
    };
  }
} catch(e) { trainingReadiness = null; }

// ── TRAINING STATUS (today) ─────────────────────────────────────────────────
// Echte response: {mostRecentTrainingStatus: {latestTrainingStatusData: {[your-device-id]: {
//   trainingStatus:5, trainingStatusFeedbackPhrase:"RECOVERY_1",
//   acuteTrainingLoadDTO: {acwrStatus:"LOW", dailyTrainingLoadAcute:56, dailyTrainingLoadChronic:176}}}},
//   mostRecentTrainingLoadBalance: {metricsTrainingLoadBalanceDTOMap: {[your-device-id]: {
//   monthlyLoadAerobicLow:97.5, monthlyLoadAerobicHigh:0, monthlyLoadAnaerobic:13.4,
//   trainingBalanceFeedbackPhrase:"AEROBIC_LOW_SHORTAGE"}}},
//   mostRecentVO2Max: {generic:null, cycling:null}}
let trainingStatus = null;
try {
  const r = await this.helpers.request({ method:'GET', url:`${BASE}/training-status?date=${today}`, json:true });
  if (r && typeof r === 'object') {
    // Haal data op uit de geneste structuur
    const statusObj = r.mostRecentTrainingStatus?.latestTrainingStatusData;
    const deviceId  = statusObj ? Object.keys(statusObj)[0] : null;
    const statusData = deviceId ? statusObj[deviceId] : null;
    const acuut = statusData?.acuteTrainingLoadDTO || {};

    const loadObj = r.mostRecentTrainingLoadBalance?.metricsTrainingLoadBalanceDTOMap;
    const loadDeviceId = loadObj ? Object.keys(loadObj)[0] : null;
    const loadData = loadDeviceId ? loadObj[loadDeviceId] : null;

    const vo2obj = r.mostRecentVO2Max || {};

    // trainingStatus nummers: 1=Piek, 2=Productief, 3=Onderhoud, 4=Herstel, 5=Herstel, 6=Onproductief, 7=Overtraining, 8=Detraining
    const statusNrMap = {1:'🏆 Piekfase', 2:'📈 Productieve fase', 3:'➡️ Onderhoud', 4:'🔄 Herstelperiode', 5:'🔄 Herstelperiode', 6:'📉 Onproductieve fase', 7:'⚠️ Overbelasting', 8:'⬇️ Conditieverlies'};

    trainingStatus = {
      statusNr:        statusData?.trainingStatus    ?? null,
      statusNL:        statusNrMap[statusData?.trainingStatus] ?? statusData?.trainingStatusFeedbackPhrase ?? null,
      feedbackPhrase:  statusData?.trainingStatusFeedbackPhrase ?? null,
      acuutLoad:       acuut.dailyTrainingLoadAcute   ?? null,
      chronischLoad:   acuut.dailyTrainingLoadChronic  ?? null,
      acwrStatus:      acuut.acwrStatus               ?? null,   // "LOW", "OPTIMAL", "HIGH"
      acwrPct:         acuut.acwrPercent              ?? null,

      // Maandelijkse belasting
      aerobicLow:      loadData?.monthlyLoadAerobicLow        ?? null,
      aerobicLowMin:   loadData?.monthlyLoadAerobicLowTargetMin ?? null,
      aerobicLowMax:   loadData?.monthlyLoadAerobicLowTargetMax ?? null,
      aerobicHigh:     loadData?.monthlyLoadAerobicHigh       ?? null,
      aerobicHighMin:  loadData?.monthlyLoadAerobicHighTargetMin ?? null,
      aerobicHighMax:  loadData?.monthlyLoadAerobicHighTargetMax ?? null,
      anaerobic:       loadData?.monthlyLoadAnaerobic          ?? null,
      anaerobicMax:    loadData?.monthlyLoadAnaerobicTargetMax  ?? null,
      balanceFeedback: loadData?.trainingBalanceFeedbackPhrase  ?? null, // "AEROBIC_LOW_SHORTAGE"

      // VO2max (null als no GPS-running)
      vo2maxGeneric:   vo2obj.generic    ?? null,
      vo2maxCycling:   vo2obj.cycling    ?? null,
    };
  }
} catch(e) { trainingStatus = null; }

// ── RACE PREDICTIONS ──────────────────────────────────────────────────────────
// Echte response: {time5K:2080000, time10K:4655000, timeHalfMarathon:11582000, timeMarathon:27187000, ...}
// TIJDEN ZIJN IN MILLISECONDEN
let racePredictions = null;
try {
  const r = await this.helpers.request({ method:'GET', url:`${BASE}/race-predictions`, json:true });
  const item = Array.isArray(r) ? r[0] : r;
  if (item && (item.time5K || item.time10K)) {
    // API geeft seconden terug (niet milliseconden)
    const msToTijd = (sec) => {
      if (!sec) return null;
      const totSec = Math.round(sec);
      const uur  = Math.floor(totSec / 3600);
      const min  = Math.floor((totSec % 3600) / 60);
      const s    = totSec % 60;
      return uur > 0
        ? `${uur}:${String(min).padStart(2,'0')}:${String(s).padStart(2,'0')}`
        : `${min}:${String(s).padStart(2,'0')}`;
    };
    const pace5K = item.time5K ? (() => {
      const secPer = Math.round(item.time5K / 5);
      return `${Math.floor(secPer/60)}:${String(secPer%60).padStart(2,'0')}/km`;
    })() : null;
    racePredictions = {
      vijfKm:        msToTijd(item.time5K),
      tienKm:        msToTijd(item.time10K),
      halveMarathon: msToTijd(item.timeHalfMarathon),
      marathon:      msToTijd(item.timeMarathon),
      pace5K,
    };
  }
} catch(e) { racePredictions = null; }

// ── FITNESS LEEFTIJD (today) ────────────────────────────────────────────────
// Echte response: {fitnessAge:51, achievableFitnessAge:47, chronologicalAge:54,
//   components: {rhr:{value:59}, vigorousDaysAvg:{value:0.3, targetValue:3},
//   vigorousMinutesAvg:{value:9.1, targetValue:75}, bmi:{value:24.5}}}
let fitnessLeeftijd = null;
try {
  const r = await this.helpers.request({ method:'GET', url:`${BASE}/fitnessleeftijd?date=${today}`, json:true });
  if (r && r.fitnessAge != null) {
    const comp = r.components || {};
    fitnessLeeftijd = {
      fitnessAge:      r.fitnessAge,
      haalbaarAge:     r.achievableFitnessAge ? Math.round(r.achievableFitnessAge) : null,
      chronologischAge: r.chronologicalAge    ?? null,
      rhr:             comp.rhr?.value        ?? null,
      intensieveDagen: comp.vigorousDaysAvg?.value   ?? null,
      intensieveDagenDoel: comp.vigorousDaysAvg?.targetValue ?? 3,
      intensieveMin:   comp.vigorousMinutesAvg?.value ?? null,
      intensieveMinDoel: comp.vigorousMinutesAvg?.targetValue ?? 75,
      bmi:             comp.bmi?.value        ?? null,
      bmiDoel:         comp.bmi?.targetValue  ?? null,
    };
  }
} catch(e) { fitnessLeeftijd = null; }

// ── PERSOONLIJKE RECORDS ──────────────────────────────────────────────────────
// typeId mapping: 1=Snelste mijl, 2=Langste afstand, 4=Snelste 5K, 5=Snelste 10K,
// 6=Snelste HM, 7=Langste activity, 10=Meeste steps, etc.
let persoonlijkeRecords = null;
try {
  const r = await this.helpers.request({ method:'GET', url:`${BASE}/persoonlijke-records`, json:true });
  if (Array.isArray(r) && r.length > 0) {
    const typeNamen = {1:'Snelste mijl', 2:'Langste afstand', 4:'Snelste 5K', 5:'Snelste 10K', 6:'Snelste halve marathon', 7:'Langste run', 9:'Max snelheid', 10:'Meeste steps'};
    persoonlijkeRecords = r.map(rec => ({
      typeId:       rec.typeId,
      typeNaam:     typeNamen[rec.typeId] ?? `Type ${rec.typeId}`,
      waarde:       Math.round(rec.value * 10) / 10,
      activityNaam: rec.activityName ?? null,
      date:        rec.actStartDateTimeInGMTFormatted?.slice(0,10) ?? null,
      activityType: rec.activityType  ?? null,
    }));
  }
} catch(e) { persoonlijkeRecords = null; }

// ── Gemiddelden & trends ──────────────────────────────────────────────────────
const geldigeSlaap    = sleepData.filter(d=>d.totaalUur>0);
const gemSlaapUur     = geldigeSlaap.length ? Math.round(geldigeSlaap.reduce((s,d)=>s+d.totaalUur,0)/geldigeSlaap.length*10)/10 : 0;
const geldigeScores   = sleepData.filter(d=>d.score);
const gemSlaapScore   = geldigeScores.length ? Math.round(geldigeScores.reduce((s,d)=>s+d.score,0)/geldigeScores.length) : 0;
const nDagen          = stapsData.length;
const gemStappen      = Math.round(stapsData.reduce((s,d)=>s+d.steps,0)/nDagen);
const bbItems         = stapsData.filter(d=>d.bbHuidig);
const gemBB           = bbItems.length ? Math.round(bbItems.reduce((s,d)=>s+d.bbHuidig,0)/bbItems.length) : null;
const dagenDoelGehaald = stapsData.filter(d=>d.stapPct>=100).length;  // van 21 dagen
const gemSedentairUur  = Math.round(stapsData.reduce((s,d)=>s+(d.sedentarySec||0),0)/nDagen/360)/10;
const totaalIntMid     = stapsData.reduce((s,d)=>s+d.intensiteitMid,0);
const totaalIntHoog    = stapsData.reduce((s,d)=>s+d.intensiteitHoog,0);
const geldigeHR        = heart rateData.filter(d=>d.rustpols);
const gemRustpols      = geldigeHR.length ? Math.round(geldigeHR.reduce((s,d)=>s+d.rustpols,0)/geldigeHR.length) : null;
const geldigeStress    = stressData.filter(d=>d.gemStress);
const gemStressWeek    = geldigeStress.length ? Math.round(geldigeStress.reduce((s,d)=>s+d.gemStress,0)/geldigeStress.length) : null;
const geldigeHRV       = hrvData.filter(d=>d.weekGem);
const gemHRV           = geldigeHRV.length ? Math.round(geldigeHRV.reduce((s,d)=>s+d.weekGem,0)/geldigeHRV.length) : null;
const geldigGewicht    = weightData.filter(d=>d.weightKg);
const weightHuidig    = geldigGewicht.length ? geldigGewicht[geldigGewicht.length-1].weightKg : null;
const weightDelta     = geldigGewicht.length>1 ? Math.round((geldigGewicht[geldigGewicht.length-1].weightKg - geldigGewicht[0].weightKg)*10)/10 : null;

const eersteHelft  = sleepData.slice(0,5).filter(d=>d.totaalUur>0);
const tweedeHelft = sleepData.slice(-7).filter(d=>d.totaalUur>0);
const sleepTrend  = eersteHelft.length && tweedeHelft.length
  ? Math.round(((tweedeHelft.reduce((s,d)=>s+d.totaalUur,0)/tweedeHelft.length)-(eersteHelft.reduce((s,d)=>s+d.totaalUur,0)/eersteHelft.length))*10)/10
  : 0;

const bestesSlaapDag      = [...sleepData].filter(d=>d.score).sort((a,b)=>b.score-a.score)[0];
const slechtesteSlaapDag  = [...sleepData].filter(d=>d.score).sort((a,b)=>a.score-b.score)[0];
const meesteStappenDag    = [...stapsData].sort((a,b)=>b.steps-a.steps)[0];

// ── AI-leesbare teksten ───────────────────────────────────────────────────────
const sleepTekst = sleepData.map((d,i) => {
  const prev = i>0 ? sleepData[i-1] : null;
  const sd = prev?.score && d.score ? (d.score-prev.score>0?`▲${d.score-prev.score}`:`▼${Math.abs(d.score-prev.score)}`) : '';
  return `${d.date}${i===6?' (VANDAAG)':''}: ${d.totaalUur}u | diep:${d.diepUur}u REM:${d.remUur}u licht:${d.lightUur}u | score:${d.score??'n.b.'} ${sd} | SpO2:${d.spo2Gem??'n.b.'}% | HRV:${d.hrv??'n.b.'} | rustpols:${d.rustpols??'n.b.'}bpm | bed:${d.bedtijd??'n.b.'} op:${d.waaktijd??'n.b.'} | adem:${d.ademhaling??'n.b.'}/min`;
}).join('\n');

const stepsTekst = stapsData.map((d,i) => {
  const status = d.stapPct>=100?'✅':d.stapPct>=75?'🟡':'❌';
  const sedUur = Math.round((d.sedentarySec||0)/360)/10;
  return `${d.date}${i===6?' (VANDAAG)':''}: ${d.steps} ${status} (${d.stapPct}%) | BB laag:${d.bbLaag??'n.b.'} hoog:${d.bbHoog??'n.b.'} | rustpols:${d.rustpols??'n.b.'}bpm | int mid:${d.intensiteitMid}min hoog:${d.intensiteitHoog}min | sedentary:${sedUur}u`;
}).join('\n');

const stressTekstWeek = stressData.map((d,i) => {
  return `${d.date}${i===6?' (VANDAAG)':''}: gem:${d.gemStress??'n.b.'} | max:${d.maxStress??'n.b.'} | rust:${d.rustMin}min laag:${d.laagMin}min midden:${d.middenMin}min hoog:${d.hoogMin}min`;
}).join('\n');

const hrvTekstWeek = hrvData.map((d,i) => {
  return `${d.date}${i===6?' (VANDAAG)':''}: weekgem:${d.weekGem??'n.b.'} | nacht:${d.previousNacht??'n.b.'} | 5-daags:${d.vijfDaags??'n.b.'} | nachMin:${d.nachMin??'n.b.'} nachMax:${d.nachMax??'n.b.'}`;
}).join('\n');

const weightTekstWeek = weightData.map((d,i) => {
  return `${d.date}${i===6?' (VANDAAG)':''}: ${d.weightKg??'no meting'}kg | BMI:${d.bmi??'n.b.'}`;
}).join('\n');

const hrZoneTekst = hrZoneData.map((d,i) => {
  const tot = d.zone1Min+d.zone2Min+d.zone3Min+d.zone4Min+d.zone5Min;
  return `${d.date}${i===6?' (VANDAAG)':''}: Z1:${d.zone1Min}min Z2:${d.zone2Min}min Z3:${d.zone3Min}min Z4:${d.zone4Min}min Z5:${d.zone5Min}min totaal:${tot}min`;
}).join('\n');

const readinessTekst = trainingReadiness
  ? `Score: ${trainingReadiness.score}/100 | Level: ${trainingReadiness.level} (${trainingReadiness.levelNL}) | Feedback: ${trainingReadiness.feedbackKort} — ${trainingReadiness.feedbackLang} | Slaapscore: ${trainingReadiness.sleepScore} | Hersteltijd: ${trainingReadiness.recoveryTime}u | Acuut load: ${trainingReadiness.acuteLoad} | HRV weekgem: ${trainingReadiness.hrv}`
  : 'Not available';

const statusTekst = trainingStatus
  ? `Status: ${trainingStatus.statusNL} (nr ${trainingStatus.statusNr}) | ACWR: ${trainingStatus.acwrStatus} ${trainingStatus.acwrPct}% | Acuut load: ${trainingStatus.acuutLoad} | Chronisch load: ${trainingStatus.chronischLoad} | Aerobic low: ${trainingStatus.aerobicLow}/${trainingStatus.aerobicLowMin}-${trainingStatus.aerobicLowMax} | Aerobic high: ${trainingStatus.aerobicHigh}/${trainingStatus.aerobicHighMin}-${trainingStatus.aerobicHighMax} | Balans: ${trainingStatus.balanceFeedback} | VO2max: ${trainingStatus.vo2maxGeneric??'n.b.'}`
  : 'Not available';

const fitnessLeeftijdTekst = fitnessLeeftijd
  ? `Fitness leeftijd: ${fitnessLeeftijd.fitnessAge} | Haalbaar: ${fitnessLeeftijd.haalbaarAge} | Chronologisch: ${fitnessLeeftijd.chronologischAge} | RHR: ${fitnessLeeftijd.rhr} | Intensieve dagen: ${fitnessLeeftijd.intensieveDagen}/${fitnessLeeftijd.intensieveDagenDoel}/week | Intensieve min: ${fitnessLeeftijd.intensieveMin}/${fitnessLeeftijd.intensieveMinDoel}/week | BMI: ${fitnessLeeftijd.bmi}`
  : 'Not available';

const recordsTekst = persoonlijkeRecords
  ? persoonlijkeRecords.map(r => `${r.typeNaam}: ${r.waarde} (${r.date})`).join(' | ')
  : 'Not available';

const raceTekst = racePredictions
  ? `5K: ${racePredictions.vijfKm} (${racePredictions.pace5K}) | 10K: ${racePredictions.tienKm} | HM: ${racePredictions.halveMarathon} | Marathon: ${racePredictions.marathon}`
  : 'No race predictions available';

// Today detectie voor activities
const activitiesRegels = activitiesTekst.split('\n');
const todayGedaan = activitiesRegels.filter(r => r.startsWith(today));

return [{ json: {
  sleepTekst, stepsTekst, stressTekstWeek, hrvTekstWeek, weightTekstWeek,
  hrZoneTekst, readinessTekst, statusTekst, fitnessLeeftijdTekst, recordsTekst, raceTekst,
  activitiesTekst, todayGedaan,
  // Ruwe arrays voor grafieken
  sleepData, stapsData, heart rateData, stressData, hrvData, weightData, hrZoneData,
  // Eenmalige objecten
  trainingReadiness, trainingStatus, fitnessLeeftijd, racePredictions, persoonlijkeRecords,
  gemiddelden: {
    sleepUur: gemSlaapUur, sleepScore: gemSlaapScore,
    stapDoel: stapsData.find(d => d.stapDoel > 0)?.stapDoel ?? 0,
    gemStappen, gemBodyBattery: gemBB,
    gemRustpols, gemStressWeek, gemHRV,
    weightHuidig, weightDelta,
    vo2maxHuidig: trainingStatus?.vo2maxGeneric ?? null,
  },
  trends: {
    sleepTrend, dagenDoelGehaald, gemSedentairUur,
    totaalIntMid, totaalIntHoog,
    bestesSlaapDag: bestesSlaapDag?.date,
    bestesSlaapScore: bestesSlaapDag?.score,
    slechtesteSlaapDag: slechtesteSlaapDag?.date,
    slechtesteSlaapScore: slechtesteSlaapDag?.score,
    meesteStappenDag: meesteStappenDag?.date,
    meesteStappen: meesteStappenDag?.steps,
  }
} }];
